import {
  formatTimecode,
  percentInClip,
  canSplit,
  trimDeltaLabel,
  getToolbarState,
} from '@/components/editor/TrimSplitToolbar';

// ─── formatTimecode ────────────────────────────────────────────────

describe('formatTimecode', () => {
  it('formats zero', () => {
    expect(formatTimecode(0)).toBe('00:00.000');
  });

  it('formats seconds and millis', () => {
    expect(formatTimecode(5250)).toBe('00:05.250');
  });

  it('formats minutes', () => {
    expect(formatTimecode(125000)).toBe('02:05.000');
  });
});

// ─── percentInClip ─────────────────────────────────────────────────

describe('percentInClip', () => {
  it('returns 0 at clip start', () => {
    expect(percentInClip(1000, 1000, 5000)).toBe(0);
  });

  it('returns 50 at midpoint', () => {
    expect(percentInClip(3500, 1000, 5000)).toBe(50);
  });

  it('clamps to 100 beyond clip end', () => {
    expect(percentInClip(8000, 1000, 5000)).toBe(100);
  });
});

// ─── canSplit ──────────────────────────────────────────────────────

describe('canSplit', () => {
  it('returns true for valid split position', () => {
    expect(canSplit(3000, 1000, 5000)).toBe(true);
  });

  it('returns false when too close to start', () => {
    expect(canSplit(1050, 1000, 5000)).toBe(false);
  });

  it('returns false when too close to end', () => {
    expect(canSplit(5950, 1000, 5000)).toBe(false);
  });
});

// ─── trimDeltaLabel ────────────────────────────────────────────────

describe('trimDeltaLabel', () => {
  it('formats positive delta', () => {
    expect(trimDeltaLabel(1500)).toBe('+1.50s');
  });

  it('formats negative delta', () => {
    expect(trimDeltaLabel(-750)).toBe('-0.75s');
  });
});

// ─── getToolbarState ───────────────────────────────────────────────

describe('getToolbarState', () => {
  it('disables all when no selection', () => {
    const state = getToolbarState({
      hasSelection: false,
      clipCount: 0,
      playheadInsideClip: false,
      canMerge: false,
    });
    expect(state.splitEnabled).toBe(false);
    expect(state.trimEnabled).toBe(false);
    expect(state.mergeEnabled).toBe(false);
    expect(state.reorderEnabled).toBe(false);
  });

  it('enables split when selection and playhead inside clip', () => {
    const state = getToolbarState({
      hasSelection: true,
      clipCount: 1,
      playheadInsideClip: true,
      canMerge: false,
    });
    expect(state.splitEnabled).toBe(true);
    expect(state.trimEnabled).toBe(true);
  });

  it('enables merge when conditions met', () => {
    const state = getToolbarState({
      hasSelection: true,
      clipCount: 2,
      playheadInsideClip: false,
      canMerge: true,
    });
    expect(state.mergeEnabled).toBe(true);
    expect(state.reorderEnabled).toBe(true);
  });

  it('enables all when all conditions met', () => {
    const state = getToolbarState({
      hasSelection: true,
      clipCount: 3,
      playheadInsideClip: true,
      canMerge: true,
    });
    expect(state.splitEnabled).toBe(true);
    expect(state.trimEnabled).toBe(true);
    expect(state.mergeEnabled).toBe(true);
    expect(state.reorderEnabled).toBe(true);
  });
});
